INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$IMAP/POP mailbox access$q$, $q$Browse full Exchange mailbox folders over IMAP or retrieve inbox-only mail over POP from any compliant client.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$SMTP send$q$, $q$Send mail through the Exchange server's outbound path using standard SMTP from any desktop or mobile client.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$CalDAV calendar sync$q$, $q$Two-way calendar synchronization including meeting invites and free/busy availability lookups.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$CardDAV contacts sync$q$, $q$Personal contact folder synchronization compatible with Apple Contacts, Thunderbird, and other CardDAV clients.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$LDAP directory search$q$, $q$Query the corporate Global Address List for name and email lookups from LDAP-aware clients.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Microsoft Graph backend (experimental)$q$, $q$A newer connection mode that uses Microsoft's modern Graph API instead of legacy EWS/WebDAV endpoints.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$OAuth2 / interactive O365 login$q$, $q$Supports modern authentication flows required by Microsoft 365 tenants with MFA enforced.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Cross-platform Java client$q$, $q$Runs identically on Linux, macOS, and Windows with native installers and packages for each.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Completely free and open-source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Lets Linux and non-Outlook users work with Exchange/Office 365 using their preferred mail client$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Actively maintained with releases addressing Microsoft's protocol deprecations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$No server-side installation or Exchange admin privileges required$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Requires manual technical setup (ports, client accounts, authentication)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$No official vendor support or SLA -- community-driven only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Depends on Microsoft continuing to expose EWS/WebDAV/Graph endpoints DavMail relies on$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Interface is protocol-level only; there is no graphical management dashboard$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Is DavMail free to use?$q$, $q$Yes. DavMail is fully free and open-source under the GPL-2.0 license, with no paid tier or subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Does DavMail work with Microsoft 365 as well as on-premise Exchange?$q$, $q$Yes, DavMail supports both on-premise Exchange servers and cloud-hosted Microsoft 365 mailboxes, including OAuth2/MFA login flows for O365 tenants.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$What email clients can I use with DavMail?$q$, $q$Any client that supports POP, IMAP, SMTP, CalDAV, CardDAV, or LDAP, including Thunderbird, Apple Mail, Apple Calendar and Contacts, Evolution, and KMail.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Do I need admin access to my company's Exchange server?$q$, $q$No. DavMail runs entirely on your own computer and connects using your normal mailbox credentials, so no server-side changes or admin rights are needed.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Is DavMail still actively maintained?$q$, $q$Yes, the project has shipped multiple releases in 2025 including an experimental Microsoft Graph API backend to stay compatible as Microsoft deprecates older Exchange protocols.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$What operating systems does DavMail support?$q$, $q$DavMail is a Java application distributed for Linux, macOS, and Windows, with native installers and packages for each platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Linux desktop users on a Windows-centric company$q$, $q$Employees running Linux who need to access a corporate Exchange mailbox use DavMail to bridge Exchange to Thunderbird or Evolution.$q$, $q$IT-savvy employees and Linux desktop users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Privacy-focused professionals avoiding Outlook$q$, $q$Users who prefer open-source mail clients like Thunderbird can keep full Exchange/O365 functionality without installing Outlook.$q$, $q$Privacy-conscious knowledge workers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Mixed-OS IT environments$q$, $q$IT departments supporting BYOD or non-Windows hardware use DavMail to avoid forcing every device onto the Outlook client.$q$, $q$IT administrators and system integrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["POP/IMAP/SMTP access","CalDAV/CardDAV sync","LDAP directory search","Cross-platform Java client","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DavMail is a free, open-source gateway that sits between a user's email client and a Microsoft Exchange or Microsoft 365 mailbox. Instead of requiring Outlook or proprietary MAPI connections, it exposes standard POP, IMAP, SMTP, CalDAV, CardDAV, and LDAP interfaces locally and translates those requests into Exchange Web Services, WebDAV, or Microsoft Graph API calls behind the scenes.$q$, $q$The project has been maintained by developer Mickael Guessant for close to two decades, released under the GPL-2.0 license, and distributed as a cross-platform Java application that runs on Linux, macOS, and Windows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DavMail supports full mailbox access over IMAP and POP, outbound mail over SMTP, calendar sync (including free/busy lookups) over CalDAV, contact sync over CardDAV, and corporate directory search over LDAP -- covering nearly everything a native Exchange client would provide.$q$, $q$Recent releases have added an experimental Microsoft Graph backend, interactive OAuth2 login for Microsoft 365 tenants that enforce MFA, restored NTLM authentication, and packaging improvements for Linux distributions, keeping the tool current as Microsoft phases out legacy Exchange endpoints.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DavMail is completely free and open-source with no paid tier, subscription, or license fee. There is no commercial entity behind it and no enterprise support contract; users rely on community forums, mailing lists, and the SourceForge issue tracker for help.$q$, $q$Because there is no cost barrier, the only real investment is setup time -- configuring local ports, client account settings, and authentication for the target Exchange or Microsoft 365 tenant.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a42ba043-aed3-4e2a-accc-c2fe75a65c67', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Google Takeout import$q$, $q$Migrate years of accumulated Google Location History data directly into Dawarich.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Live GPS tracking$q$, $q$Stream real-time location from mobile apps such as OwnTracks, Overland, and GPSLogger.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Heatmap visualization$q$, $q$See density of visited areas rendered as an interactive heatmap over a map interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Fog of War mode$q$, $q$A game-like map mode that only reveals areas you have actually visited, gradually uncovering your travel history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Trip and visit statistics$q$, $q$Track distance traveled, countries and cities visited, and time spent in different locations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Docker Compose self-hosting$q$, $q$Deploy the full stack (Rails app, PostgreSQL/PostGIS, Sidekiq) with a single Docker Compose file.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Dawarich Cloud managed hosting$q$, $q$Optional paid, GDPR-compliant EU-hosted managed instance for users who don't want to self-host.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Dawarich Atlas offline maps$q$, $q$A companion self-hosted offline mapping project for homelab deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Full feature set available for free when self-hosted, with no functionality paywall$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Direct, well-supported migration path from Google Takeout data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Strong open-source community with active GitHub and Discord engagement$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$AGPL license guarantees continued access to source code and modifications$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Self-hosting requires Docker and basic server administration knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$As a young project, long-term company stability and roadmap are less established than larger vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$AGPL licensing may deter some commercial integrators from building closed-source derivatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Company-level details (team size, formal entity) are not publicly disclosed$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Is Dawarich free?$q$, $q$Yes, self-hosting Dawarich is completely free with the full feature set. A paid Dawarich Cloud option exists for users who prefer managed hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Can I import my existing Google Timeline data?$q$, $q$Yes, Dawarich supports importing historical location data directly from a Google Takeout export, as well as OwnTracks and GPX files.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$What license is Dawarich released under?$q$, $q$Dawarich is released under the AGPL-3.0 license, which allows free self-hosted use and requires source disclosure if you offer a modified version as a network service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$How do I run Dawarich?$q$, $q$Dawarich is distributed as a Docker Compose stack built on Ruby on Rails, PostgreSQL with PostGIS, and Sidekiq, deployable on your own server or a hosting provider like AWS Marketplace or ElfHosted.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Who created Dawarich?$q$, $q$Dawarich was created by developer Evgenii Burmakin (GitHub handle Freika); the name comes from the German phrase 'da war ich,' meaning 'I was there.'$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$What is Fog of War mode?$q$, $q$It's a map visualization mode that only reveals areas of the map you have actually visited, similar to fog-of-war mechanics in strategy video games.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Migrating away from Google Timeline$q$, $q$Users concerned about Google restricting or discontinuing Timeline's cloud backup import their history into Dawarich to retain full control.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Homelab personal analytics$q$, $q$Self-hosting enthusiasts add Dawarich to an existing homelab stack alongside tools like Immich or Nextcloud to track and visualize their movement history.$q$, $q$Self-hosting and homelab enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Travel and trip logging$q$, $q$Travelers use Dawarich's statistics and Fog of War map to track countries and cities visited over time.$q$, $q$Frequent travelers and digital nomads$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set","Unlimited data storage on your own infrastructure","Docker Compose deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Cloud Lite$q$, $q$€49.99$q$, $q$yearly$q$, NULL, $q$["Managed EU hosting","GDPR-compliant data storage","Free trial","Refund window"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$Cloud Pro$q$, $q$€17.99$q$, $q$monthly$q$, NULL, $q$["Managed EU hosting","Encrypted data in transit and at rest","Priority support","Free trial"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dawarich is an open-source, self-hostable application that replaces Google Timeline, letting users import, store, and visualize their own location history on infrastructure they control. It was created by developer Evgenii Burmakin (GitHub handle Freika) and takes its name from the German phrase 'da war ich' -- 'I was there.'$q$, $q$Built with Ruby on Rails, PostgreSQL/PostGIS, and Sidekiq background jobs, Dawarich ships as a Docker Compose stack and has grown to over 9,000 GitHub stars, reflecting strong demand for privacy-first alternatives as Google restricts Timeline's cloud features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can import historical data from Google Takeout, OwnTracks, and GPX files, or stream live location from mobile GPS-logging apps. The interface offers heatmaps, trip statistics, and a distinctive 'Fog of War' mode that progressively reveals the map as new areas are visited.$q$, $q$Dawarich is released under the AGPL-3.0 license: self-hosting for personal or internal use is free and unrestricted, while anyone offering a modified version as a network service must release their source code changes as well.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Dawarich is entirely free with the full feature set included. For users who don't want to manage their own server, Dawarich Cloud offers managed hosting on a Lite plan (around EUR 49.99/year) or a Pro plan (around EUR 17.99/month), both with a free trial and refund window.$q$, $q$Dawarich Cloud infrastructure is hosted in European data centers with encryption in transit and at rest and GDPR compliance, appealing to users who want managed convenience without sacrificing data protection.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
