INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5b11a993-2f55-40d0-abfa-c3ac9710bd48', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Native Mac and iOS apps$q$, $q$True native applications for Mac, iPhone, and iPad rather than a wrapped web app, with deep OS-level integration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Offline access and sync$q$, $q$View and edit records without an internet connection; changes sync automatically once back online.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Apple Mail, Contacts, and Calendar integration$q$, $q$Link emails, files, and calendar events directly to CRM records inside apps you already use.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Sales pipeline tracking$q$, $q$Manage opportunities through customizable sales stages with reporting on pipeline health.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Project and task management$q$, $q$Organize projects with tasks, pipelines, and team assignments alongside CRM data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Contact and company management$q$, $q$Centralize contact history, notes, and relationship data across your team.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Team collaboration$q$, $q$Shared visibility into contacts, projects, and opportunities across a Daylite Cloud team.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Reporting and dashboards$q$, $q$Track sales and project performance with built-in reporting tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Deep, native integration with Mac, iPhone, and iPad unmatched by web-first CRMs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Full offline functionality with automatic sync when reconnected$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Long track record -- in continuous development since 2002$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Certified consultant network available for implementation and training$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Apple-only -- no Windows or Android support, ruling out mixed-platform teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Per-user pricing can add up for larger teams compared to some web-first CRMs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Smaller company than major CRM vendors, meaning a narrower support/partner ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Learning curve for teams new to structured CRM workflows$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Is Daylite available for Windows?$q$, $q$No. Daylite is built exclusively for Mac, iPhone, and iPad and does not support Windows or Android.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$How much does Daylite cost?$q$, $q$Daylite Cloud starts at roughly $25/user/month for the CRM plan, with Sales and Projects around $40/user/month and Business around $55/user/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Does Daylite work offline?$q$, $q$Yes, Daylite offers full offline access on Mac and iOS, with changes syncing automatically once you're back online.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Is there a free trial?$q$, $q$Yes, Marketcircle offers a 30-day free trial of Daylite Cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Who makes Daylite?$q$, $q$Daylite is made by Marketcircle, a Canadian software company headquartered in Markham, Ontario, founded in 1999.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Can Daylite integrate with Apple Mail and Calendar?$q$, $q$Yes, Daylite integrates natively with Apple Mail, Contacts, and Calendar, letting you link emails and events directly to CRM records.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Mac-based small business sales teams$q$, $q$Small businesses already standardized on Apple hardware use Daylite to track leads, opportunities, and client relationships natively.$q$, $q$Small business owners and sales teams on Mac$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Professional services and consultancies$q$, $q$Agencies and consultancies use Daylite's project and CRM features together to manage client work from lead to delivery.$q$, $q$Consultants, agencies, and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Field professionals on iPhone/iPad$q$, $q$Real estate agents and financial advisors use Daylite's offline mobile apps to access client data while traveling.$q$, $q$Real estate agents and financial advisors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$CRM$q$, $q$$25$q$, $q$per user/month$q$, NULL, $q$["Contact and company management","Calendar and email integration","Mobile and offline access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Sales and Projects$q$, $q$$40$q$, $q$per user/month$q$, NULL, $q$["Everything in CRM","Sales pipeline tracking","Project and task management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$Business$q$, $q$$55$q$, $q$per user/month$q$, NULL, $q$["Everything in Sales and Projects","Advanced reporting","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Daylite is a native CRM and project management app built exclusively for Mac, iPhone, and iPad by Marketcircle, a Canadian software company founded in 1999 and headquartered in Markham, Ontario. Daylite itself launched in 2002 as one of the first CRM products purpose-built for Mac OS X.$q$, $q$In 2015 Marketcircle introduced Daylite Cloud, a hosted subscription version, and the company has since fully transitioned away from its legacy self-hosted license model to a pure SaaS business, while keeping the native Apple app experience that differentiates it from web-first CRMs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Daylite covers contact and company management, sales pipeline and opportunity tracking, project and task management, calendaring, and email integration, all built as a true native macOS/iOS app rather than a wrapped web page, with full offline access and sync.$q$, $q$Its deep integration with Apple Mail, Contacts, and Calendar lets users link emails and files directly to CRM records and manage their business without leaving familiar Apple apps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Daylite Cloud is sold in three tiers: a CRM plan starting around $25/user/month, a Sales and Projects plan around $40/user/month, and a Business plan around $55/user/month, all billed per user.$q$, $q$New customers get a 30-day free trial, and Marketcircle periodically offers a 25% discount on the first 12 months for customers choosing monthly billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Browser-based IDE$q$, $q$Write, test, and preview SQL transformation models directly in a hosted development environment.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Managed job scheduling and orchestration$q$, $q$Schedule and monitor transformation runs without managing your own orchestration infrastructure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$CI/CD for data pipelines$q$, $q$Automatically test and validate code changes in isolated environments before merging to production.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$dbt Semantic Layer$q$, $q$Define business metrics once and reuse them consistently across BI tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$dbt Copilot (AI assistance)$q$, $q$AI-assisted generation, explanation, and debugging of dbt transformation code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Automated testing and documentation$q$, $q$Built-in data quality tests and auto-generated documentation with lineage graphs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Role-based access control and SSO$q$, $q$Enterprise-grade governance and identity management for larger teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Multi-warehouse support$q$, $q$Works with Snowflake, BigQuery, Databricks, Redshift, Microsoft Fabric, and other major cloud warehouses.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Built on dbt Core, the de facto open-source standard for SQL-based data transformation$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Huge community ecosystem of packages, documentation, and trained analytics engineers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Strong governance and CI/CD features for enterprise data teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Deep integration across all major cloud data warehouses$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Usage-based overage billing makes total cost harder to predict than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Free Developer plan has a hard cap on monthly model builds$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Requires SQL and data-engineering fluency; not a no-code tool for business users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Is dbt Cloud free?$q$, $q$dbt Cloud offers a free Developer plan for individual use with a monthly cap on model builds; paid Starter and Enterprise tiers unlock team collaboration and higher usage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$What's the difference between dbt Core and dbt Cloud?$q$, $q$dbt Core is the free, open-source command-line transformation engine. dbt Cloud is dbt Labs' managed SaaS layer on top of it, adding an IDE, scheduling, CI/CD, the Semantic Layer, and enterprise governance features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$How much does dbt Cloud cost?$q$, $q$dbt Cloud starts free for individual developers; the Starter plan is roughly $100 per seat per month with usage-based overage, and Enterprise/Enterprise+ pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Which data warehouses does dbt Cloud support?$q$, $q$dbt Cloud integrates with all major cloud data warehouses, including Snowflake, Google BigQuery, Databricks, Amazon Redshift, and Microsoft Fabric.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Who founded dbt Labs?$q$, $q$dbt Labs was founded in 2016 in Philadelphia as Fishtown Analytics by Tristan Handy, Drew Banin, and Connor McArthur, and later rebranded to dbt Labs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Does dbt Cloud include AI features?$q$, $q$Yes, dbt Cloud offers dbt Copilot, an AI assistant for generating, explaining, and debugging dbt transformation code.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Analytics engineering teams$q$, $q$Data teams use dbt Cloud to apply software engineering practices -- version control, testing, code review -- to SQL transformation logic.$q$, $q$Analytics engineers and data teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Enterprise data governance$q$, $q$Larger organizations use dbt Cloud's RBAC, SSO, and CI/CD features to govern who can change production data models and how.$q$, $q$Enterprise data platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Consistent business metrics across BI tools$q$, $q$Organizations use the dbt Semantic Layer to define metrics once and ensure consistent numbers across Looker, Tableau, and other BI tools.$q$, $q$BI and analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Developer$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Individual use","Monthly model build cap","Core dbt functionality"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Starter$q$, $q$$100$q$, $q$per seat/month$q$, NULL, $q$["Team collaboration","Job scheduling and CI/CD","Usage-based overage billing beyond threshold"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$Enterprise / Enterprise+$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Advanced governance and RBAC","SSO","Semantic Layer","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$dbt Cloud is dbt Labs' managed SaaS platform built around the open-source dbt (data build tool) framework, which lets analytics engineers write data transformations as version-controlled SQL. dbt Labs began as Fishtown Analytics, a Philadelphia data consultancy founded in 2016 by Tristan Handy, Drew Banin, and Connor McArthur.$q$, $q$The company has raised roughly $414 million total, including a $222 million Series D in 2022 at a $4.2 billion valuation led by Altimeter Capital, with strategic backing from Databricks, Snowflake, and Salesforce Ventures. dbt Labs remains headquartered in Philadelphia with a largely remote global workforce of roughly 900-1,200 employees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$dbt Cloud adds a browser-based IDE, managed job scheduling and orchestration, CI/CD for testing changes before merge, the dbt Semantic Layer for reusable metric definitions, dbt Copilot for AI-assisted development, and enterprise governance features like RBAC and SSO on top of the free, open-source dbt Core engine.$q$, $q$The underlying model is that transformations are modular SQL statements executed directly inside the warehouse, with automated dependency resolution, data quality testing, and auto-generated documentation and lineage graphs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$dbt Cloud offers a free Developer plan for individuals with a monthly cap on model builds, a Starter plan at roughly $100/seat/month with usage-based overage billing beyond a higher build threshold, and custom-priced Enterprise and Enterprise+ tiers for governance, security, and platform-scale needs.$q$, $q$Because pricing blends per-seat costs with usage-based compute consumption, total spend depends on team size, job frequency, and which advanced features (Semantic Layer, Copilot, CI/CD) are enabled.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('50be4027-11b3-43fe-b1ca-c6caad422481', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Cooperative 64-player servers$q$, $q$Teams work together through obstacle-course maps rather than competing in deathmatch modes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Global skill-based ranking$q$, $q$Tracks individual and team completion times across thousands of community-made maps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Cross-platform clients$q$, $q$Native builds for Windows, macOS, and Linux, distributed via the DDNet website, Steam, and Linux package repositories.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Community map pool$q$, $q$A large, continually growing library of community-submitted maps that go through structured testing before official release.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Open-source codebase$q$, $q$Full source code available under BSD/zlib licensing, allowing anyone to run their own servers or build derivative mods.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Lightweight 2D engine$q$, $q$Inherits Teeworlds' low system requirements, making it accessible on modest hardware.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Discord and forum community$q$, $q$Active, long-running social infrastructure for map-making contests, discussion, and player coordination.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Multi-language support$q$, $q$Community-maintained translations including English, German, Russian, French, and Portuguese.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Completely free with no purchases, subscriptions, or ads$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Cooperative gameplay is unusual and welcoming compared to typical competitive shooters$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Very lightweight, running well on low-end hardware$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Over a decade of continuous, active development and a large existing map library$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Niche genre with a learning curve around precision grappling-hook movement$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$No formal company or support channel -- entirely volunteer-run$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Visual style is deliberately retro/minimal, which won't appeal to all players$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Smaller player base than mainstream multiplayer games, limiting server variety at times$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Is DDraceNetwork (DDNet) free to play?$q$, $q$Yes, DDNet is completely free with no purchases, subscriptions, or ads, and is available on its website, Steam, and Linux package repositories.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$What is DDNet based on?$q$, $q$DDNet is a mod of Teeworlds, specifically building on an earlier cooperative Teeworlds mod called DDRace.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$How many players can play together?$q$, $q$DDNet supports cooperative gameplay with up to 64 players simultaneously on a single server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Is DDNet open source?$q$, $q$Yes, DDNet's source code is publicly available on GitHub under permissive BSD/zlib licensing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$What platforms does DDNet support?$q$, $q$DDNet has native clients for Windows, macOS, and Linux.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Who runs DDNet?$q$, $q$DDNet is maintained entirely by a volunteer community of developers and administrators rather than a commercial company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Cooperative precision platforming$q$, $q$Players team up to complete grappling-hook-based obstacle course maps, competing on completion time rather than against each other.$q$, $q$Casual and competitive multiplayer gamers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Community map-making$q$, $q$Map creators design and submit new obstacle courses that go through community testing before official release.$q$, $q$Level designers and modders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Low-spec free multiplayer gaming$q$, $q$Players without high-end hardware use DDNet's lightweight 2D engine to access full multiplayer gameplay.$q$, $q$Players with older or budget hardware$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full game access","All community maps","Global ranking system","Cross-platform play"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DDraceNetwork (DDNet) is a free, open-source cooperative platformer game built as a modification of Teeworlds, letting teams of up to 64 players work together through physics-based obstacle course maps using grappling hooks and other Teeworlds tools rather than competing against each other.$q$, $q$The project traces its roots to an earlier Teeworlds mod called DDRace, and formally began as DDraceNetwork on July 17, 2013, when community members organized an alternative to the earlier DDmaX server community. It has since become the dominant hub of the DDRace/cooperative Teeworlds community.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DDNet supports up to 64 simultaneous cooperative players per server, a global skill-based ranking system tracking completion times across thousands of community-made maps, and cross-platform clients for Windows, macOS, and Linux distributed via its own site, Steam, and Linux package repositories.$q$, $q$The codebase is written in C++ and released under permissive BSD/zlib open-source licensing consistent with Teeworlds, allowing anyone to inspect the code, run their own servers, or build derivative mods such as DDNetPP.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DDNet is entirely free with no in-app purchases, subscriptions, or ads. It is maintained by a volunteer community rather than a commercial company, funded through donations and community goodwill.$q$, $q$There is no paid tier of any kind -- every feature, map, and ranking system is available to all players at no cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acb4633f-9c12-4fe7-abe7-4e2c008d1d04', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$No-code CPQ configuration$q$, $q$Build product catalogs, pricing rules, and approval logic through a visual interface without custom development.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Guided selling playbooks$q$, $q$Structured workflows that walk sales reps through error-resistant quote creation for complex deals.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$DealRoom$q$, $q$An interactive, shared workspace where buyers and sellers negotiate and finalize proposals and contracts together.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Adaptive pricebooks$q$, $q$Support for usage-based, tiered, and fixed pricing models combined within a single deal.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Contract lifecycle management (CLM)$q$, $q$Manage contract creation, negotiation, and approval as part of the broader quote-to-revenue process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Subscription and usage billing$q$, $q$Manage recurring revenue billing tied directly to closed deals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$CRM and ERP integrations$q$, $q$Native API connections to Salesforce, Microsoft Dynamics, ERPs, and e-commerce platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$AI-assisted quoting$q$, $q$AI features that help generate quote language, suggest pricing, and streamline approval routing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$No-code administration reduces reliance on Salesforce development resources$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$DealRoom improves buyer experience and speeds up deal negotiation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Supports complex, multi-dimensional pricing including usage-based models$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Extends beyond CPQ into contract lifecycle management and billing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$No published pricing -- requires a sales conversation for any quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Initial product catalog and pricing rule setup requires meaningful configuration work$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Smaller ecosystem than Salesforce CPQ for organizations deep in the Salesforce platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Best suited to mid-market/enterprise teams with pricing complexity, less so very small teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$How much does DealHub CPQ cost?$q$, $q$DealHub does not publish list pricing; costs are custom-quoted based on modules and team size, with third-party estimates suggesting typical starting costs around $500-$1,000 per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Who founded DealHub?$q$, $q$DealHub was founded in 2014 by Eyal Elbahary, Alon Lubin, and Eyal Orgil, originally operating under the name Valooto.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$What is a DealRoom?$q$, $q$The DealRoom is DealHub's interactive, shared digital workspace where buyers and sellers review proposals, negotiate terms, and finalize contracts together.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Does DealHub integrate with Salesforce?$q$, $q$Yes, DealHub integrates natively with Salesforce and Microsoft Dynamics CRMs, as well as ERPs and e-commerce platforms via its API.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Is DealHub a no-code platform?$q$, $q$Yes, DealHub lets sales operations teams configure product catalogs, pricing rules, and approval workflows through a visual interface without custom development.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$What are DealHub's main competitors?$q$, $q$DealHub competes primarily with Salesforce CPQ, Oracle CPQ, PandaDoc CPQ, and sales enablement platforms like Seismic and Showpad.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Complex multi-product pricing$q$, $q$B2B software companies with bundled or usage-based pricing use DealHub to configure accurate, guided quotes without manual spreadsheets.$q$, $q$Sales operations and revenue teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Buyer-seller collaboration on deals$q$, $q$Sales teams use the DealRoom to negotiate and finalize contracts collaboratively with buyers in a shared digital space.$q$, $q$Enterprise sales reps and account executives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Subscription revenue management$q$, $q$Companies use DealHub's CLM and billing features to manage the full lifecycle from quote to recurring revenue.$q$, $q$RevOps and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$CPQ+$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["No-code CPQ configuration","Guided selling","CRM integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$CPQ + CLM$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Everything in CPQ+","Contract lifecycle management","DealRoom collaboration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$Quote-to-Revenue$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Everything in CPQ + CLM","Subscription and usage billing","Full revenue lifecycle automation"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DealHub is a configure-price-quote (CPQ) and quote-to-revenue platform that helps B2B sales teams configure complex pricing, generate accurate quotes and contracts, route approvals, and manage subscription billing. It was founded in 2014 by Eyal Elbahary, Alon Lubin, and Eyal Orgil, originally operating as Valooto before rebranding to DealHub.$q$, $q$The company is headquartered in Tel Aviv, Israel, with US operations including an Austin, Texas presence, and employs roughly 250 to 320 people as of 2026, having raised total funding reported around $84.5 million.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DealHub's no-code configuration platform lets sales operations teams build product catalogs, pricing rules, discount guardrails, and approval logic without custom development, supporting usage-based, tiered, and fixed pricing within a single deal.$q$, $q$Its DealRoom feature gives buyers and sellers a shared, interactive workspace to review proposals and finalize contracts, and the DealHub API connects CPQ data to CRMs like Salesforce and Microsoft Dynamics, ERPs, and e-commerce platforms for full quote-to-revenue automation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DealHub does not publish list pricing; packages are grouped as CPQ+, CPQ plus Contract Lifecycle Management, and a full Quote-to-Revenue bundle, all requiring a custom sales quote. Third-party estimates put typical starting costs around $500-$1,000 per month depending on team size and modules.$q$, $q$Rather than traditional Basic/Professional/Enterprise tiers, DealHub uses modular, needs-based packaging aligned to deal complexity and integration requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67e99a7f-6ac4-41d8-bead-00bd3c3b6aaa', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Log-based change capture$q$, $q$Reads database transaction/replication logs directly rather than polling, minimizing performance impact and capturing every change including deletes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Broad database support$q$, $q$Dedicated connectors for MySQL, PostgreSQL, MongoDB, SQL Server, Oracle, Db2, Cassandra, and Vitess.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Kafka Connect integration$q$, $q$Runs natively inside Kafka Connect clusters, publishing structured change events to Kafka topics.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Debezium Server$q$, $q$Standalone runtime that streams changes to non-Kafka destinations like Amazon Kinesis, Google Pub/Sub, Apache Pulsar, or Redis.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Debezium Platform$q$, $q$A newer management layer for simplifying deployment, monitoring, and operations of Debezium pipelines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Exactly-ordered event streams$q$, $q$Delivers change events in the precise order they occurred in the source database transaction log.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Outbox pattern support$q$, $q$Popularized reliable event-driven microservice patterns built on database change streams instead of dual writes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Open, extensible connector framework$q$, $q$Built on the Kafka Connect API, allowing custom connectors and community contributions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Completely free and open-source under the permissive Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Log-based capture avoids performance issues and missed-delete problems of polling or triggers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Broad support across nearly every major relational and NoSQL database$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Backed by a large community and years of production use at scale, now under neutral foundation governance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Requires operating and tuning a Kafka Connect cluster, which adds operational complexity$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$No official managed offering directly from the Debezium project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Steeper learning curve for teams unfamiliar with Kafka and CDC concepts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Some database connectors require enabling specific replication features that DBAs may need to configure$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Is Debezium free?$q$, $q$Yes, Debezium is completely free and open-source under the Apache License 2.0, with no official paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$What databases does Debezium support?$q$, $q$Debezium supports MySQL, PostgreSQL, MongoDB, SQL Server, Oracle, Db2, Cassandra, and Vitess through dedicated connectors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Does Debezium require Apache Kafka?$q$, $q$Debezium is built natively on Kafka Connect, but Debezium Server allows streaming changes to non-Kafka destinations like Kinesis, Pub/Sub, Pulsar, or Redis without a full Kafka Connect deployment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Who created Debezium?$q$, $q$Debezium was started around 2015-2016 by Randall Hauch, a software engineer at Red Hat, and later grew into a community project now governed by the Commonhaus Foundation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$How does Debezium capture database changes?$q$, $q$Debezium reads a database's internal transaction or replication log directly rather than polling, capturing every insert, update, and delete in the exact order it occurred.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Are there managed alternatives to running Debezium myself?$q$, $q$Yes, commercial platforms such as Confluent Cloud, Decodable, and Redpanda offer managed CDC services built on or compatible with Debezium's connector ecosystem.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Real-time data synchronization$q$, $q$Teams stream database changes into search indexes, caches, or data warehouses to keep downstream systems continuously up to date.$q$, $q$Data engineers and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Event-driven microservices$q$, $q$Engineering teams use Debezium's outbox pattern support to reliably publish domain events without dual-write consistency issues.$q$, $q$Backend and microservices engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Database migration and replication$q$, $q$Organizations use Debezium to replicate data between databases or migrate to a new platform with minimal downtime.$q$, $q$Database administrators and migration teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["All database connectors","Debezium Server","Community support","Apache 2.0 licensing"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Debezium is an open-source distributed platform for change data capture (CDC), streaming row-level database inserts, updates, and deletes in real time via Apache Kafka Connect. It was started in 2015-2016 by Randall Hauch, a Red Hat software engineer, and grew into one of the most widely used pieces of open-source data infrastructure in the Kafka ecosystem.$q$, $q$Debezium is licensed under the permissive Apache License 2.0 and, after years of being supported as part of Red Hat Integration, the project announced a governance transition to the vendor-neutral Commonhaus Foundation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Debezium reads a database's internal transaction/replication log (MySQL binlog, PostgreSQL WAL, MongoDB oplog, SQL Server CDC tables) rather than polling, capturing every change including deletes with minimal impact on the source database, in the exact order it occurred.$q$, $q$Dedicated connectors exist for MySQL, PostgreSQL, MongoDB, SQL Server, Oracle, Db2, Cassandra, and Vitess, and the ecosystem includes Debezium Server for streaming to non-Kafka destinations and the newer Debezium Platform for simplified deployment and operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Debezium itself is entirely free and open-source under Apache 2.0, with no licensing cost or vendor lock-in. Organizations that want fully managed CDC without operating their own Kafka Connect infrastructure typically pay for commercial platforms like Confluent Cloud, Decodable, or Redpanda that build on or compete with Debezium.$q$, $q$There is no official Debezium-branded paid tier; monetization happens entirely through the surrounding commercial ecosystem rather than the project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8fe9ecc9-4076-431c-b5a3-fbde13581137', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$128+ Ansible roles$q$, $q$A broad, curated library covering databases, web servers, DNS, mail, monitoring, and virtualization technologies.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Inventory-driven customization$q$, $q$Roles expose behavior through Ansible inventory variables so the same code produces different configurations per environment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Project directories$q$, $q$Self-contained folders bundling inventory, playbooks, and roles, letting one team manage multiple independent environments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Security-conscious defaults$q$, $q$Roles are built with secure, production-ready defaults reflecting the Debian project's free-software and security culture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Virtualization support$q$, $q$Roles for deploying KVM/libvirt, Docker, and LXC-based virtualization environments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Extensive documentation$q$, $q$A versioned, comprehensive documentation site covering every role and playbook in detail.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Debian/Ubuntu-first design$q$, $q$Purpose-built for Debian-family distributions rather than generic cross-distribution automation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$PyPI-distributed CLI$q$, $q$The debops command-line tool is installed via standard Python packaging for easy setup.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Completely free and open-source under GPL-3.0-or-later$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Large, internally consistent, well-tested role library rather than a fragmented marketplace$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Over a decade of continuous maintenance by the same founding project$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Strong security-conscious defaults reflecting the Debian community's ethos$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Debian/Ubuntu-focused, offering less value for Red Hat-family or other distributions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Requires Ansible and general infrastructure-as-code familiarity to use effectively$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$No commercial support contract or SLA available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Smaller contributor base than mainstream configuration management tools like Ansible Galaxy's most popular roles$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Is DebOps free to use?$q$, $q$Yes, DebOps is completely free and open-source under the GPL-3.0-or-later license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$What is DebOps built on?$q$, $q$DebOps is built entirely on top of Ansible, providing a curated library of more than 128 roles rather than replacing Ansible itself.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Which operating systems does DebOps support?$q$, $q$DebOps is designed specifically for Debian and Ubuntu Linux infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Who created DebOps?$q$, $q$DebOps was founded in October 2013 by Polish system administrator Maciej Delmanowski.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$How do I install DebOps?$q$, $q$The debops command-line tool is distributed via PyPI (Python packaging) and works alongside Ansible roles pulled from the project's GitHub repositories.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$What are 'project directories' in DebOps?$q$, $q$They are self-contained folders that bundle their own Ansible inventory, playbooks, and roles, letting one team manage multiple environments independently from a shared role library.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Data center automation$q$, $q$System administrators use DebOps to bootstrap and manage consistent, secure Debian/Ubuntu server fleets without writing custom Ansible roles from scratch.$q$, $q$System administrators and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Multi-environment infrastructure management$q$, $q$Teams use project directories to manage production, staging, and client environments independently from a shared role library.$q$, $q$Infrastructure and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Homelab and personal server automation$q$, $q$Individual power users apply DebOps roles to automate personal VPS fleets and home lab servers.$q$, $q$Self-hosting enthusiasts and individual sysadmins$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["128+ Ansible roles","Project directories","Community documentation and support","GPL-3.0-or-later licensing"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DebOps is a free, open-source collection of Ansible roles and playbooks for bootstrapping and managing Debian- or Ubuntu-based IT infrastructure, describing itself as 'your Debian-based data center in a box.' It was founded in October 2013 by Polish system administrator Maciej Delmanowski.$q$, $q$The project is released under the GPL-3.0-or-later license, mirroring the Debian project's strong free-software ethos, and is built entirely as a curated library on top of Ansible rather than a replacement for it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DebOps ships more than 128 individually documented, independently usable Ansible roles covering SQL and NoSQL databases, web servers, DNS, mail systems, monitoring, and virtualization technologies like KVM/libvirt, Docker, and LXC.$q$, $q$Roles are built for heavy customization through Ansible inventory variables, and DebOps' 'project directories' concept lets one administrator manage multiple independent environments -- production, staging, personal -- from the same shared role library without configurations interfering with each other.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f37df20-288c-490c-8a89-5a00b2c6478e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DebOps is entirely free and open-source with no commercial tier, company, or support contract behind it. It is installed via the debops Python package on PyPI combined with Ansible roles pulled from the project's GitHub repositories.$q$, $q$Support is community-driven through documentation at docs.debops.org and the project's GitHub organization rather than a paid vendor helpdesk.$q$]::text[], 2);
